<?php namespace App\Repositories\Attendance;use App\Repositories\BaseRepository;use App\Models\Attendance\LeaveType;use Illuminate\Database\Eloquent\Collection;class LeaveTypeRepository extends BaseRepository{    public function __construct(LeaveType $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByCode(string $code): ?LeaveType    {        return $this->query()->where('code', $code)->first();    }    public function findByName(string $name): ?LeaveType    {        return $this->query()->where('name', $name)->first();    }    public function getActiveLeaveTypes(): Collection    {        return $this->query()->where('is_active', true)->get();    }    public function getPaidLeaveTypes(): Collection    {        return $this->query()->where('is_paid', true)->get();    }    public function getByCategory(string $category): Collection    {        return $this->findByField('category', $category);    }    public function searchLeaveTypes(string $keyword): Collection    {        return $this->query()->where('name', 'like', "%{$keyword}%")->orWhere('code', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->get();    }}